<script>
export default {
  name: 'SettingsView',
  data() {
    return {
      settingsList: [
        { title: 'Camera', value: true },
        { title: 'Microphone', value: false },
        // Add more settings as needed
      ],
    };
  },
  methods: {
    handleSettingChanged(event, index) {
      const currentIndex = this.currentIndex;
      if (index === 0 || event.target.value === '') return;

      if (currentIndex === 0) {
        this.$route.meta.title = 'Camera and Microphone Status';
      } else {
        this.$route.meta.title = `Camera: ${this.settingsList[index - 1].value ? 'ON' : 'OFF'}`;
      }

      this.currentIndex = index;
    },
  },
};
